12	/**
13	 * Computes the next generation of live cells from the current live cells,
14	 * applying Conway's rules.
15	 */
16	export function nextGeneration(cells: Cell[]): Cell[] {
17	  return cells.filter((cell) => {
18	    const liveNeighbors = countLiveNeighbors(cells, cell);
19	    return liveNeighbors === 2 || liveNeighbors === 3;
20	  });
21	}
